import{_ as n,C as s,o,c as l,E as t,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Austria Legal Rights","description":"Legal rights for transgender people in Austria","frontmatter":{"layout":"doc","title":"Austria Legal Rights","description":"Legal rights for transgender people in Austria"},"headers":[],"relativePath":"europe/austria/legal-rights.md","filePath":"europe/austria/legal-rights.md","lastUpdated":null}'),c={name:"europe/austria/legal-rights.md"};function h(u,e,g,m,p,f){const i=s("Badge");return o(),l("div",null,[t(i,{variant:"yellow"},{default:a(()=>[...e[0]||(e[0]=[r("Self-ID since 2024",-1)])]),_:1}),t(i,{variant:"green"},{default:a(()=>[...e[1]||(e[1]=[r("Strong Anti-Discrimination",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-austria" tabindex="-1">Legal Rights in Austria <a class="header-anchor" href="#legal-rights-in-austria" aria-label="Permalink to &quot;Legal Rights in Austria&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Austria adopted a <strong>self-determination model</strong> for legal gender recognition in 2024, replacing the previous medicalized system. This was a landmark reform following years of advocacy.</p><h3 id="current-process-since-2024" tabindex="-1">Current Process (since 2024) <a class="header-anchor" href="#current-process-since-2024" aria-label="Permalink to &quot;Current Process (since 2024)&quot;">​</a></h3><ul><li><strong>Self-declaration</strong> to the civil registry (Standesamt)</li><li>No medical certificates, diagnosis, surgery, or therapy required</li><li>No waiting period</li><li>Minimum age: 14 (with parental consent under 18)</li><li>Process is administrative — typically completed within a few weeks</li></ul><h3 id="previous-system-before-2024" tabindex="-1">Previous System (before 2024) <a class="header-anchor" href="#previous-system-before-2024" aria-label="Permalink to &quot;Previous System (before 2024)&quot;">​</a></h3><p>Previously, Austria required:</p><ul><li>Psychiatric diagnosis of gender dysphoria</li><li>Court application and hearing</li><li>Medical reports from multiple specialists</li><li>This was widely criticized as invasive and pathologizing</li></ul><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes are submitted alongside the gender recognition application</li><li>Or can be done independently through the civil registry</li><li>No medical requirements</li><li>Simple administrative process</li><li>Usually processed within 2-4 weeks</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Austria has comprehensive anti-discrimination protections:</p><ul><li><strong>Equal Treatment Act (Gleichbehandlungsgesetz)</strong> — Prohibits discrimination based on gender</li><li><strong>Gender identity</strong> is recognized as falling under gender discrimination protections</li><li><strong>Employment</strong> — Full protection in all employment aspects (hiring, promotion, dismissal)</li><li><strong>Education</strong> — Protection in schools and universities</li><li><strong>Goods and Services</strong> — Access to services without discrimination</li><li><strong>Housing</strong> — Protection in rental and purchase</li><li><strong>Social Security</strong> — Equal access to benefits</li></ul><p>The <strong>Equal Treatment Commission</strong> (Gleichbehandlungskommission) handles discrimination complaints.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>Austria&#39;s Criminal Code includes hate crime provisions with enhanced penalties</li><li>Gender identity is recognized as a protected characteristic</li><li>Covers violent crimes, threats, harassment, and hate speech</li><li>Reporting and prosecution rates are generally good</li><li>Vienna has specialized police units for hate crime</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated gender markers on Austrian passports and IDs are recognized internationally</li><li>Austrian passports can use updated marker without additional requirements</li><li>Third gender / &quot;divers&quot; marker available since 2018</li><li>Birth certificate updates follow the self-declaration process</li><li>Documents accepted across the EU</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Status</th></tr></thead><tbody><tr><td>Gender Recognition</td><td>Self-ID (since 2024)</td></tr><tr><td>Surgery Required</td><td>No</td></tr><tr><td>Third Gender</td><td>Available (&quot;divers&quot;)</td></tr><tr><td>Anti-Discrimination</td><td>Strong</td></tr><tr><td>Hate Crime Protections</td><td>Good</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.help.gv.at/" target="_blank" rel="noreferrer">Standesamt (Civil Registry)</a></li><li><a href="https://www.hosiwien.at/" target="_blank" rel="noreferrer">HOSI Wien</a></li><li><a href="https://trans-austria.org/" target="_blank" rel="noreferrer">Trans* Austria</a></li><li><a href="https://vimoe.at/" target="_blank" rel="noreferrer">VIMÖ - Association of LGBTQ+ Organisations</a></li><li><a href="https://www.gleichbehandlungskommission.at/" target="_blank" rel="noreferrer">Austrian Equal Treatment Commission</a></li></ul>',22))])}const y=n(c,[["render",h]]);export{w as __pageData,y as default};
